#!/usr/bin/env php
<?php
declare(strict_types=1);
use App\Core\Cloud\CloudPath; use App\Core\Database\PdoFactory;
$root=dirname(__DIR__); require_once $root.'/vendor/autoload.php'; $app=require $root.'/bootstrap/app.php';
$o=getopt('', ['tenant:','user:','message:','dry-run','apply']); $tenantId=(int)($o['tenant']??0); $userId=(int)($o['user']??0); $messageId=(int)($o['message']??0); $dryRun=array_key_exists('dry-run',$o)||!array_key_exists('apply',$o);
if($tenantId<=0||$userId<=0||$messageId<=0){fwrite(STDERR,"Uso: php scripts/mail-attachments-repair-cloud-links.php --tenant=1 --user=1 --message=16 --dry-run|--apply\n"); exit(1);} $pdo=PdoFactory::make((array)($app['config']['database']??[]));
$st=$pdo->prepare('SELECT ea.*,m.user_id FROM mail_external_attachments ea INNER JOIN mail_messages m ON m.id=ea.message_id AND m.tenant_id=ea.tenant_id WHERE ea.tenant_id=:t AND m.user_id=:u AND ea.message_id=:m AND ea.cloud_file_id IS NULL AND ea.import_status IN ("pending","failed") ORDER BY ea.id ASC'); $st->execute([':t'=>$tenantId,':u'=>$userId,':m'=>$messageId]); $rows=$st->fetchAll(PDO::FETCH_ASSOC)?:[];
$repairable=0;$repaired=0;$errors=[]; foreach($rows as $r){$id=(int)$r['id'];$name=(string)($r['original_filename']?:('attachment-'.$id));$safe=preg_replace('/[^A-Za-z0-9._-]/','_',$name)?:('attachment-'.$id);$keyPrefix='users/'.$userId.'/mail/inbound/attachments/'.$messageId.'/';
$q=$pdo->prepare('SELECT id,mime_type,size_bytes FROM cloud_files WHERE tenant_id=:t AND user_id=:u AND origin_module="mail" AND origin_table="mail_external_attachments" AND origin_id=:oid ORDER BY id DESC LIMIT 1');$q->execute([':t'=>$tenantId,':u'=>$userId,':oid'=>$id]);$cf=$q->fetch(PDO::FETCH_ASSOC);
if(!is_array($cf)){$q=$pdo->prepare('SELECT id,mime_type,size_bytes FROM cloud_files WHERE tenant_id=:t AND user_id=:u AND s3_key LIKE :prefix ORDER BY id DESC LIMIT 1');$q->execute([':t'=>$tenantId,':u'=>$userId,':prefix'=>$keyPrefix.'%']);$cf=$q->fetch(PDO::FETCH_ASSOC);} if(!is_array($cf)){continue;} $repairable++;
if($dryRun){continue;} try{$pdo->beginTransaction(); $cloudId=(int)$cf['id']; $chk=$pdo->prepare('SELECT id FROM mail_attachments WHERE tenant_id=:t AND message_id=:m AND cloud_file_id=:c LIMIT 1');$chk->execute([':t'=>$tenantId,':m'=>$messageId,':c'=>$cloudId]); if((int)($chk->fetchColumn()?:0)<=0){$ins=$pdo->prepare('INSERT INTO mail_attachments (tenant_id,message_id,cloud_file_id,original_filename,content_id,disposition,mime_type,size_bytes,created_at) VALUES (:t,:m,:c,:f,NULL,:d,:mt,:s,NOW())');$ins->execute([':t'=>$tenantId,':m'=>$messageId,':c'=>$cloudId,':f'=>$name,':d'=>in_array((string)($r['disposition']??''),['inline','attachment'],true)?(string)$r['disposition']:'attachment',':mt'=>(string)($r['mime_type']??$cf['mime_type']??'application/octet-stream'),':s'=>max(0,(int)($r['size_bytes']??$cf['size_bytes']??0))]);}
$up=$pdo->prepare('UPDATE mail_external_attachments SET cloud_file_id=:c, import_status="imported", imported_at=NOW(), error_message=NULL WHERE id=:id AND tenant_id=:t');$up->execute([':c'=>$cloudId,':id'=>$id,':t'=>$tenantId]); $pdo->commit(); $repaired++; }catch(Throwable $e){if($pdo->inTransaction()){$pdo->rollBack();}$errors[]=['external_attachment_id'=>$id,'reason'=>'repair_failed'];}}
echo json_encode(['ok'=>true,'message_id'=>$messageId,'dry_run'=>$dryRun,'candidates'=>count($rows),'repairable'=>$repairable,'repaired'=>$repaired,'errors'=>$errors],JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE).PHP_EOL;
